import * as events from 'events';
import Event from './Event';

export default class EventContainer {

    /**
     * A regular NodeJS event emitter for untyped
     * events
     * @type {EventEmitter}
     */
    public untyped = new events.EventEmitter();

    /**
     * Removes all listeners of all events that are top level
     * members of the EventContainer
     */
    removeAllListeners() {
        this.untyped.removeAllListeners();
        this.forEachTypedEvent( (event) => {
            event.removeAllListeners();
        });
    }

    /**
     * Iterates through all event properties of this event container
     * @param {Function} handler
     */
    forEachTypedEvent(handler: (event: Event<any>) => void) {
        Object.keys(this).forEach( (key) => {
            let value = this[key];
            if (value.constructor && value.constructor.name === 'Event') {
                handler(value);
            }
        });
    }
}